+    #[test]
+    fn expand_tilde_tilde_slash_path() {
+        let result = expand_tilde("~/Documents/file.txt");
+        if let Some(home) = dirs::home_dir() {
+            assert_eq!(result, home.join("Documents/file.txt"));
+        }
+    }
